package April_o6_2022;

public class Elseif {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int n1=10;
		int n2=20;
		int n3=47;
		if(n1>=n2 && n1>=n3)
		{
			System.out.print("n1 is greater");
		}
		else if(n2>n1 && n2>n3)
		{
			System.out.print("n2 is greater");
		}
		else
		{
			System.out.print("n3 is greater");
		}

	}

}
